const state = {
  year: "All",
  region: "All",
  retailer: "All",
  method: "All",
  product: "All",
};

const methodColors = {
  "In-store": "#111827",
  "Outlet": "#2563eb",
  "Online": "#16a34a",
};

const moneyShort = new Intl.NumberFormat("en-US", {
  style: "currency",
  currency: "USD",
  notation: "compact",
  maximumFractionDigits: 1,
});

const numberShort = new Intl.NumberFormat("en-US", {
  notation: "compact",
  maximumFractionDigits: 2,
});

const numberFull = new Intl.NumberFormat("en-US");

const titleCase = (value) => String(value || "").replace(/\b\w/g, (char) => char.toUpperCase());

function formatMoney(value) {
  if (!Number.isFinite(value)) return "$0";
  return moneyShort.format(value);
}

function formatNumber(value) {
  if (!Number.isFinite(value)) return "0";
  return numberShort.format(value);
}

function formatPercent(value) {
  if (!Number.isFinite(value)) return "0.0%";
  return `${(value * 100).toFixed(1)}%`;
}

function sumBy(rows, key) {
  return rows.reduce((sum, row) => sum + Number(row[key] || 0), 0);
}

function groupRows(rows, key) {
  return rows.reduce((acc, row) => {
    const groupKey = typeof key === "function" ? key(row) : row[key];
    if (!acc[groupKey]) acc[groupKey] = [];
    acc[groupKey].push(row);
    return acc;
  }, {});
}

function aggregate(rows, key) {
  return Object.entries(groupRows(rows, key))
    .map(([name, values]) => {
      const sales = sumBy(values, "sales");
      const profit = sumBy(values, "profit");
      const units = sumBy(values, "units");
      return {
        name,
        sales,
        profit,
        units,
        margin: sales ? profit / sales : 0,
        share: 0,
        count: values.length,
      };
    })
    .sort((a, b) => b.sales - a.sales);
}

function uniqueValues(key) {
  return [...new Set(ADIDAS_DATA.map((row) => row[key]))].sort((a, b) => String(a).localeCompare(String(b)));
}

function fillSelect(selectId, values, label = "All") {
  const select = document.getElementById(selectId);
  select.innerHTML = "";
  const allOption = document.createElement("option");
  allOption.value = "All";
  allOption.textContent = label;
  select.appendChild(allOption);

  values.forEach((value) => {
    const option = document.createElement("option");
    option.value = value;
    option.textContent = value;
    select.appendChild(option);
  });
}

function initFilters() {
  fillSelect("yearFilter", uniqueValues("year"), "All Years");
  fillSelect("regionFilter", uniqueValues("region"), "All Regions");
  fillSelect("retailerFilter", uniqueValues("retailer"), "All Retailers");
  fillSelect("methodFilter", uniqueValues("method"), "All Methods");
  fillSelect("productFilter", uniqueValues("product"), "All Products");

  const bindings = [
    ["yearFilter", "year"],
    ["regionFilter", "region"],
    ["retailerFilter", "retailer"],
    ["methodFilter", "method"],
    ["productFilter", "product"],
  ];

  bindings.forEach(([selectId, key]) => {
    document.getElementById(selectId).addEventListener("change", (event) => {
      state[key] = event.target.value;
      updateDashboard();
    });
  });

  document.getElementById("resetFilters").addEventListener("click", () => {
    Object.keys(state).forEach((key) => (state[key] = "All"));
    bindings.forEach(([selectId]) => (document.getElementById(selectId).value = "All"));
    updateDashboard();
  });
}

function getFilteredRows() {
  return ADIDAS_DATA.filter((row) => {
    return (
      (state.year === "All" || String(row.year) === String(state.year)) &&
      (state.region === "All" || row.region === state.region) &&
      (state.retailer === "All" || row.retailer === state.retailer) &&
      (state.method === "All" || row.method === state.method) &&
      (state.product === "All" || row.product === state.product)
    );
  });
}

function updateKPIs(rows) {
  const sales = sumBy(rows, "sales");
  const profit = sumBy(rows, "profit");
  const units = sumBy(rows, "units");
  const margin = sales ? profit / sales : 0;
  const avgPrice = units ? sales / units : 0;

  document.getElementById("kpiSales").textContent = formatMoney(sales);
  document.getElementById("kpiProfit").textContent = formatMoney(profit);
  document.getElementById("kpiUnits").textContent = formatNumber(units);
  document.getElementById("kpiMargin").textContent = formatPercent(margin);

  document.getElementById("kpiSalesSub").textContent = `${numberFull.format(rows.length)} transactions analyzed`;
  document.getElementById("kpiProfitSub").textContent = `${formatPercent(margin)} weighted margin`;
  document.getElementById("kpiUnitsSub").textContent = `${formatMoney(avgPrice)} average sales per unit`;
  document.getElementById("kpiMarginSub").textContent = `${formatMoney(profit)} profit from ${formatMoney(sales)} sales`;
}

function updateInsights(rows) {
  const sales = sumBy(rows, "sales");
  const profit = sumBy(rows, "profit");
  const margin = sales ? profit / sales : 0;
  const retailers = aggregate(rows, "retailer");
  const regions = aggregate(rows, "region");
  const products = aggregate(rows, "product");
  const methods = aggregate(rows, "method");

  const topRetailer = retailers[0] || { name: "-", sales: 0 };
  const bestMarginRegion = [...regions].sort((a, b) => b.margin - a.margin)[0] || { name: "-", margin: 0 };
  const topProduct = products[0] || { name: "-", sales: 0 };
  const bestMethod = [...methods].sort((a, b) => b.margin - a.margin)[0] || { name: "-", margin: 0 };

  const retailerShare = sales ? topRetailer.sales / sales : 0;
  const summary = `The selected view generated ${formatMoney(sales)} in sales and ${formatMoney(profit)} in operating profit, with a weighted margin of ${formatPercent(margin)}. ${topRetailer.name} is the strongest retail partner, contributing ${formatPercent(retailerShare)} of sales. ${topProduct.name} is the leading product category, while ${bestMethod.name} shows the strongest channel efficiency based on margin.`;
  document.getElementById("executiveSummary").textContent = summary;

  const pills = [
    ["Top Retailer", topRetailer.name],
    ["Top Product", topProduct.name],
    ["Best Margin Region", `${bestMarginRegion.name} · ${formatPercent(bestMarginRegion.margin)}`],
    ["Best Channel", `${bestMethod.name} · ${formatPercent(bestMethod.margin)}`],
  ];

  document.getElementById("insightPills").innerHTML = pills
    .map(([label, value]) => `<div class="insight-pill"><span>${label}</span><strong>${value}</strong></div>`)
    .join("");

  const lowMarginRegion = [...regions].sort((a, b) => a.margin - b.margin)[0] || { name: "-", margin: 0 };
  const topUnitMethod = [...methods].sort((a, b) => b.units - a.units)[0] || { name: "-", units: 0 };
  const highPotentialProduct = [...products].sort((a, b) => (b.sales * b.margin) - (a.sales * a.margin))[0] || { name: "-" };

  const recommendations = [
    `Prioritize ${topRetailer.name} as the key retail account because it currently drives the largest sales contribution.`,
    `Scale ${bestMethod.name} activation because it delivers the strongest operating margin at ${formatPercent(bestMethod.margin)}.`,
    `Use ${topProduct.name} as the hero product category for campaign planning and stock allocation.`,
    `Review pricing, discounting, and distribution costs in ${lowMarginRegion.name}, the lowest-margin region at ${formatPercent(lowMarginRegion.margin)}.`,
    `Protect volume from ${topUnitMethod.name}, which moves the highest unit count, while increasing basket value through bundles or premium products.`,
  ];

  document.getElementById("recommendationList").innerHTML = recommendations
    .map((text) => `<li>${text}</li>`)
    .join("");
}

function emptyChart(containerId, message = "No data available for the selected filters") {
  document.getElementById(containerId).innerHTML = `<div class="empty-state">${message}</div>`;
}

function linePath(points) {
  if (!points.length) return "";
  return points.map((point, index) => `${index === 0 ? "M" : "L"}${point.x},${point.y}`).join(" ");
}

function drawTrendChart(rows) {
  if (!rows.length) return emptyChart("trendChart");
  const grouped = aggregate(rows, "month").sort((a, b) => a.name.localeCompare(b.name));
  const monthLabels = Object.fromEntries(rows.map((row) => [row.month, row.monthLabel]));

  const width = 840;
  const height = 340;
  const padding = { top: 28, right: 34, bottom: 54, left: 72 };
  const chartWidth = width - padding.left - padding.right;
  const chartHeight = height - padding.top - padding.bottom;
  const maxValue = Math.max(...grouped.map((d) => Math.max(d.sales, d.profit)), 1);
  const yMax = maxValue * 1.12;
  const xStep = grouped.length > 1 ? chartWidth / (grouped.length - 1) : chartWidth;

  const pointsSales = grouped.map((d, index) => ({
    x: padding.left + index * xStep,
    y: padding.top + chartHeight - (d.sales / yMax) * chartHeight,
  }));
  const pointsProfit = grouped.map((d, index) => ({
    x: padding.left + index * xStep,
    y: padding.top + chartHeight - (d.profit / yMax) * chartHeight,
  }));

  const ticks = [0, 0.25, 0.5, 0.75, 1];
  const grid = ticks.map((tick) => {
    const y = padding.top + chartHeight - tick * chartHeight;
    return `<line class="grid-line" x1="${padding.left}" y1="${y}" x2="${width - padding.right}" y2="${y}" />
      <text class="tick-label" x="${padding.left - 12}" y="${y + 4}" text-anchor="end">${formatMoney(yMax * tick)}</text>`;
  }).join("");

  const labelEvery = grouped.length > 14 ? 3 : grouped.length > 8 ? 2 : 1;
  const labels = grouped.map((d, index) => {
    if (index % labelEvery !== 0 && index !== grouped.length - 1) return "";
    const x = padding.left + index * xStep;
    return `<text class="tick-label" x="${x}" y="${height - 18}" text-anchor="middle">${monthLabels[d.name].replace(" ", " '")}</text>`;
  }).join("");

  const pointMarkers = pointsSales.map((p, index) => {
    const d = grouped[index];
    return `<circle cx="${p.x}" cy="${p.y}" r="4" fill="#2563eb"><title>${monthLabels[d.name]} Sales: ${formatMoney(d.sales)}</title></circle>`;
  }).join("") + pointsProfit.map((p, index) => {
    const d = grouped[index];
    return `<circle cx="${p.x}" cy="${p.y}" r="4" fill="#16a34a"><title>${monthLabels[d.name]} Profit: ${formatMoney(d.profit)}</title></circle>`;
  }).join("");

  document.getElementById("trendChart").innerHTML = `
    <svg viewBox="0 0 ${width} ${height}" role="img" aria-label="Monthly sales and profit trend">
      ${grid}
      <path class="line-sales" d="${linePath(pointsSales)}" />
      <path class="line-profit" d="${linePath(pointsProfit)}" />
      ${pointMarkers}
      ${labels}
    </svg>`;
}

function drawHorizontalBars(containerId, rows, key, limit = 8) {
  if (!rows.length) return emptyChart(containerId);
  const grouped = aggregate(rows, key).slice(0, limit);
  const maxSales = Math.max(...grouped.map((d) => d.sales), 1);
  const rowHeight = 52;
  const width = 760;
  const height = 44 + grouped.length * rowHeight;
  const labelWidth = 210;
  const barWidth = width - labelWidth - 150;

  const rowsSvg = grouped.map((d, index) => {
    const y = 30 + index * rowHeight;
    const widthSales = Math.max((d.sales / maxSales) * barWidth, 4);
    return `
      <text class="value-label" x="0" y="${y + 14}">${d.name}</text>
      <text class="tick-label" x="0" y="${y + 32}">${formatPercent(d.margin)} margin · ${formatNumber(d.units)} units</text>
      <rect class="muted-bar" x="${labelWidth}" y="${y}" width="${barWidth}" height="18" rx="9"></rect>
      <rect class="bar-fill" x="${labelWidth}" y="${y}" width="${widthSales}" height="18" rx="9"></rect>
      <text class="value-label" x="${labelWidth + barWidth + 16}" y="${y + 14}">${formatMoney(d.sales)}</text>`;
  }).join("");

  document.getElementById(containerId).innerHTML = `
    <svg viewBox="0 0 ${width} ${height}" role="img" aria-label="Sales by ${key}">
      ${rowsSvg}
    </svg>`;
}

function drawMethodChart(rows) {
  if (!rows.length) return emptyChart("methodChart");
  const methods = aggregate(rows, "method");
  const total = sumBy(methods, "sales");
  const radius = 74;
  const circumference = 2 * Math.PI * radius;
  let offset = 0;

  const circles = methods.map((method) => {
    const share = total ? method.sales / total : 0;
    const dash = share * circumference;
    const circle = `<circle cx="110" cy="110" r="${radius}" fill="none" stroke="${methodColors[method.name] || "#64748b"}" stroke-width="28" stroke-dasharray="${dash} ${circumference - dash}" stroke-dashoffset="${-offset}" transform="rotate(-90 110 110)"><title>${method.name}: ${formatMoney(method.sales)} (${formatPercent(share)})</title></circle>`;
    offset += dash;
    return circle;
  }).join("");

  const list = methods.map((method) => {
    const share = total ? method.sales / total : 0;
    return `
      <div class="method-item">
        <span class="method-dot" style="background:${methodColors[method.name] || "#64748b"}"></span>
        <div><strong>${method.name}</strong><small>${formatMoney(method.sales)} · ${formatPercent(method.margin)} margin</small></div>
        <span>${formatPercent(share)}</span>
      </div>`;
  }).join("");

  document.getElementById("methodChart").innerHTML = `
    <svg viewBox="0 0 220 220" role="img" aria-label="Sales method mix donut chart">
      <circle cx="110" cy="110" r="${radius}" fill="none" stroke="#e5e7eb" stroke-width="28"></circle>
      ${circles}
      <text x="110" y="105" class="donut-center-label">${formatMoney(total)}</text>
      <text x="110" y="126" class="donut-sub-label">Total Sales</text>
    </svg>
    <div class="method-list">${list}</div>`;
}

function drawRegionList(rows) {
  if (!rows.length) {
    document.getElementById("regionChart").innerHTML = `<div class="empty-state">No data available for the selected filters</div>`;
    return;
  }
  const regions = aggregate(rows, "region");
  const maxSales = Math.max(...regions.map((region) => region.sales), 1);
  const html = regions.map((region) => `
    <div class="region-card">
      <div>
        <div class="region-name">${region.name}</div>
        <div class="region-meta">${formatMoney(region.profit)} profit</div>
      </div>
      <div class="region-bar-track"><div class="region-bar" style="width:${Math.max((region.sales / maxSales) * 100, 2)}%"></div></div>
      <div class="margin-badge">${formatPercent(region.margin)}</div>
    </div>
  `).join("");
  document.getElementById("regionChart").innerHTML = html;
}

function updateStateTable(rows) {
  const states = aggregate(rows, "state");
  if (!states.length) {
    document.getElementById("stateTable").innerHTML = `<tr><td colspan="5">No data available for the selected filters.</td></tr>`;
    return;
  }

  const totalSales = sumBy(rows, "sales");
  const avgMargin = totalSales ? sumBy(rows, "profit") / totalSales : 0;

  const selectedStates = states
    .map((stateItem) => {
      let status = "Strong";
      let className = "status-strong";
      if (stateItem.margin < avgMargin - 0.05 && stateItem.sales > totalSales / Math.max(states.length, 1)) {
        status = "Margin Risk";
        className = "status-risk";
      } else if (stateItem.margin < avgMargin) {
        status = "Review";
        className = "status-review";
      }
      return { ...stateItem, status, className };
    })
    .sort((a, b) => b.sales - a.sales)
    .slice(0, 10);

  document.getElementById("stateTable").innerHTML = selectedStates.map((stateItem) => `
    <tr>
      <td>${stateItem.name}</td>
      <td>${formatMoney(stateItem.sales)}</td>
      <td>${formatMoney(stateItem.profit)}</td>
      <td>${formatPercent(stateItem.margin)}</td>
      <td><span class="status-badge ${stateItem.className}">${stateItem.status}</span></td>
    </tr>
  `).join("");
}

function updateDashboard() {
  const rows = getFilteredRows();
  updateKPIs(rows);
  updateInsights(rows);
  drawTrendChart(rows);
  drawMethodChart(rows);
  drawHorizontalBars("retailerChart", rows, "retailer", 6);
  drawHorizontalBars("productChart", rows, "product", 6);
  drawRegionList(rows);
  updateStateTable(rows);
}

initFilters();
updateDashboard();

window.addEventListener("resize", () => {
  window.clearTimeout(window.__adidasResizeTimer);
  window.__adidasResizeTimer = window.setTimeout(updateDashboard, 120);
});
